import Big from 'big.js';

// 基于 big.js [https://github.com/MikeMcl/big.js] 提供各种常见的高精度计算方法

/**
 * 高精度加法
 * @param args
 * @return arg1 + arg2 + .... + argn
 */
export function add(...args: (string | number)[]) {
    const [_1, ...n] = args;
    return n.reduce((p, c) => p.add(c), new Big(_1));
}

/**
 * 高精度减法
 * @param args
 * @return arg1 - arg2 - .... - argn
 */
export function minus(...args: (string | number)[]) {
    const [_1, ...n] = args;
    return n.reduce((p, c) => p.minus(c), new Big(_1));
}

/**
 * 高精度乘法
 * @param args
 * @return arg1 * arg2 * .... * argn
 */
export function mul(...args: (string | number)[]) {
    const [_1, ...n] = args;
    return n.reduce((p, c) => p.mul(c), new Big(_1));
}

/**
 * 高精度除法
 * @param args
 * @return arg1 / arg2 / .... / argn
 */
export function div(...args: (string | number)[]) {
    const [_1, ...n] = args;
    return n.reduce((p, c) => p.div(c), new Big(_1));
}